using System;
using System.Collections.Generic;
using System.Xml;
using System.Xml.Schema;

public static Dictionary<string, string> ParseConfigurationXml(string xmlContent)
{
    var settings = new Dictionary<string, string>();
    
    try
    {
        var xmlDoc = new XmlDocument();
        var settingsReader = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            XmlResolver = null,
            ValidationType = ValidationType.None
        };
        
        using (var reader = XmlReader.Create(new System.IO.StringReader(xmlContent), settingsReader))
        {
            xmlDoc.Load(reader);
        }
        
        foreach (XmlNode node in xmlDoc.SelectNodes("//setting"))
        {
            if (node.Attributes?["name"] != null && node.InnerText != null)
            {
                string key = node.Attributes["name"].Value;
                string value = node.InnerText.Trim();
                
                if (!string.IsNullOrEmpty(key))
                {
                    settings[key] = value;
                }
            }
        }
    }
    catch (XmlException ex)
    {
        throw new ArgumentException("Invalid XML format", nameof(xmlContent), ex);
    }
    catch (Exception ex)
    {
        throw new InvalidOperationException("Failed to parse configuration", ex);
    }
    
    return settings;
}